+// Return the workstation position for a given room type
+export function getWorkstationPosition(roomType: string): { x: number; y: number } {
+  // Define workstation positions relative to room coordinates (0-1 range)
+  // These are offsets to be scaled and added to room position in agents.tsx
+  switch (roomType) {
+    case 'scribe':
+      return { x: 0.5, y: 0.45 };
+    case 'judge':
+      return { x: 0.5, y: 0.45 };
+    case 'blacksmith':
+      return { x: 0.5, y: 0.45 };
+    default:
+      return { x: 0.5, y: 0.45 };
+  }
+}
+
+// Smoothly interpolate between two points
+export function lerp(start: number, end: number, t: number): number {
+  return start + (end - start) * t;
+}
+
+// Character state for movement interpolation
+interface CharacterState {
+  x: number;
+  y: number;
+  targetX: number;
+  targetY: number;
+  lastUpdate: number;
+}
+
+const characterStates = new Map<string, CharacterState>();
+
+// Update character position smoothly towards target
+export function updateCharacterPosition(
+  id: string,
+  currentX: number,
+  currentY: number,
+  targetX: number,
+  targetY: number,
+  deltaTime: number,
+): { x: number; y: number } {
+  let state = characterStates.get(id);
+  if (!state) {
+    state = { x: currentX, y: currentY, targetX, targetY, lastUpdate: 0 };
+    characterStates.set(id, state);
+  }
+  state.targetX = targetX;
+  state.targetY = targetY;
+
+  // Interpolate position with smoothing factor
+  const smoothing = 0.1;
+  state.x = lerp(state.x, targetX, smoothing);
+  state.y = lerp(state.y, targetY, smoothing);
+  return { x: state.x, y: state.y };
+}
